  testimonials: {
    testimonials: [
      { name: 'Nom', role: 'Client', quote: 'Excellent service!', avatar: '' }
    ]
  },
  gallery: {
    images: [
      { url: '', alt: '', caption: '' }
    ]
  }
};

export function getDefaultContent(type) {
  return DEFAULT_CONTENT[type] || {};
}
